// Copies MediaPipe's self-contained WASM runtime out of node_modules into
// public/, so the Bone Editor's auto-rig feature can load it from the same
// origin as the app instead of the jsdelivr/unpkg CDN paths MediaPipe's
// examples default to (some deployment environments block those hosts).
// Not committed to git — regenerated by `npm install` like node_modules/dist.
import { existsSync, mkdirSync, copyFileSync, readdirSync } from 'node:fs';
import { fileURLToPath } from 'node:url';
import path from 'node:path';

const root = path.dirname(fileURLToPath(new URL('.', import.meta.url)));
const src = path.join(root, 'node_modules', '@mediapipe', 'tasks-vision', 'wasm');
const dest = path.join(root, 'public', 'mediapipe-wasm');

if (!existsSync(src)) {
  console.warn('[copy-mediapipe-wasm] source not found, skipping:', src);
  process.exit(0);
}
mkdirSync(dest, { recursive: true });
for (const file of readdirSync(src)) {
  copyFileSync(path.join(src, file), path.join(dest, file));
}
console.log('[copy-mediapipe-wasm] copied', readdirSync(dest).length, 'files to public/mediapipe-wasm');
